refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/coins_gray.jpg"));
smoothed = imgaussianblur(image, [11 11], 3);

mask = smoothed < 125;
mask = imclose(mask, imcreatese("ellipse", 5, 5)) <> 0;
mask = imopen(mask, imcreatese("ellipse", 3, 3)) <> 0;

distance = imbwdist(mask, "euclidean");
coinCores = distance > 0.55 * max(distance);
overlay = imoverlaymask(image, coinCores .* 1, [255 0 0], 0.65, %t);

figure("figure_size", [1000 700]);
subplot(2, 2, 1);
imshow(image);
xtitle("Original coin image");

subplot(2, 2, 2);
imshow(mask);
xtitle("Segmented foreground");

subplot(2, 2, 3);
imshow(distance, hot(64));
xtitle("Distance to nearest background pixel");

subplot(2, 2, 4);
imshow(overlay);
xtitle("High-distance coin centers");
gcf().background = -2;
